"use client";

import { CheckCircle, XCircle, Trash2, Search, Medal, Loader2, User } from "lucide-react";
import { useEffect, useState } from "react";
import api from "@/lib/api";
import toast from "react-hot-toast";

export default function AdminCoachesPage() {
    const [coaches, setCoaches] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");

    useEffect(() => {
        const fetchCoaches = async () => {
            try {
                const res = await api.get('/coaches');
                setCoaches(res.data);
            } catch (error) {
                toast.error("Failed to load coaches");
            } finally {
                setLoading(false);
            }
        };
        fetchCoaches();
    }, []);

    const handleUpdateStatus = async (id: string, status: string) => {
        try {
            await api.put(`/coaches/${id}/status`, { status });
            setCoaches(coaches.map(c => c._id === id ? { ...c, status } : c));
            toast.success(`Coach ${status.toLowerCase()}`);
        } catch (error) {
            toast.error("Failed to update status");
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this coach?")) return;
        try {
            await api.delete(`/coaches/${id}`);
            setCoaches(coaches.filter(c => c._id !== id));
            toast.success("Coach deleted");
        } catch (error) {
            toast.error("Failed to delete coach");
        }
    };

    const filteredCoaches = coaches.filter(c =>
        c.coachName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        c.licenseType?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800">Licensed Coaches Directory</h2>
                    <p className="text-sm text-gray-500 mt-1">Review coaching credentials and manage state-certified personnel.</p>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full">
                <div className="p-4 border-b border-gray-100 flex flex-col sm:flex-row gap-4 justify-between bg-gray-50/50">
                    <div className="relative w-full sm:w-96">
                        <Search className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <input
                            type="text"
                            placeholder="Search coaches by name or license..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all text-sm"
                        />
                    </div>
                </div>

                <div className="overflow-x-auto w-full">
                    <table className="w-full text-left text-sm whitespace-nowrap min-w-[800px]">
                        <thead className="bg-gray-50 text-gray-500 font-semibold border-b border-gray-100">
                            <tr>
                                <th className="px-6 py-4">Coach Name</th>
                                <th className="px-6 py-4">Highest License</th>
                                <th className="px-6 py-4">Primary Club (if any)</th>
                                <th className="px-6 py-4">Exp.</th>
                                <th className="px-6 py-4">Status</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {loading ? (
                                <tr>
                                    <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                                        <div className="flex items-center justify-center gap-2">
                                            <Loader2 className="w-5 h-5 animate-spin text-primary" />
                                            <span>Loading coaches...</span>
                                        </div>
                                    </td>
                                </tr>
                            ) : filteredCoaches.length === 0 ? (
                                <tr>
                                    <td colSpan={6} className="px-6 py-8 text-center text-gray-500">No coaches found</td>
                                </tr>
                            ) : (
                                filteredCoaches.map((coach) => (
                                    <tr key={coach._id} className="hover:bg-gray-50/50 transition-colors">
                                        <td className="px-6 py-4 font-bold text-gray-800">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-full bg-gray-100 flex shrink-0 items-center justify-center text-gray-400 overflow-hidden">
                                                    {coach.passportPhotographUrl ? (
                                                        <img src={coach.passportPhotographUrl} alt={coach.coachName} className="w-full h-full object-cover" />
                                                    ) : (
                                                        <User className="w-4 h-4" />
                                                    )}
                                                </div>
                                                <span className="truncate max-w-[150px]">{coach.coachName}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-gray-600">
                                            <div className="flex items-center gap-1.5 font-medium">
                                                <Medal className="w-4 h-4 text-secondary shrink-0" />
                                                <span className="truncate max-w-[120px]">{coach.licenseType}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-gray-500 truncate max-w-[150px]">{coach.currentClub || 'Unattached'}</td>
                                        <td className="px-6 py-4 text-gray-500">{coach.yearsOfExperience} Years</td>
                                        <td className="px-6 py-4">
                                            <span className={`px-3 py-1 rounded-full text-xs font-bold ${coach.status === 'Approved' ? 'bg-green-100 text-green-700' :
                                                coach.status === 'Pending' ? 'bg-yellow-100 text-yellow-800' :
                                                    'bg-red-100 text-red-700'
                                                }`}>
                                                {coach.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center justify-end gap-2">
                                                {coach.status !== 'Approved' && (
                                                    <button onClick={() => handleUpdateStatus(coach._id, 'Approved')} className="p-2 text-green-600 hover:bg-green-50 rounded-lg transition-colors" title="Approve License">
                                                        <CheckCircle className="w-5 h-5" />
                                                    </button>
                                                )}
                                                {coach.status !== 'Rejected' && (
                                                    <button onClick={() => handleUpdateStatus(coach._id, 'Rejected')} className="p-2 text-orange-600 hover:bg-orange-50 rounded-lg transition-colors" title="Reject Application">
                                                        <XCircle className="w-5 h-5" />
                                                    </button>
                                                )}
                                                <button onClick={() => handleDelete(coach._id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete Record">
                                                    <Trash2 className="w-5 h-5" />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

"use client";

import { CheckCircle, XCircle, Trash2, Search, Trophy, Loader2, Image as ImageIcon } from "lucide-react";
import { useEffect, useState } from "react";
import api from "@/lib/api";
import toast from "react-hot-toast";

export default function AdminCompetitionsPage() {
    const [competitions, setCompetitions] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");

    useEffect(() => {
        const fetchCompetitions = async () => {
            try {
                const res = await api.get('/competitions');
                setCompetitions(res.data);
            } catch (error) {
                toast.error("Failed to load competitions");
            } finally {
                setLoading(false);
            }
        };
        fetchCompetitions();
    }, []);

    const handleUpdateStatus = async (id: string, status: string) => {
        try {
            await api.put(`/competitions/${id}/status`, { status });
            setCompetitions(competitions.map(c => c._id === id ? { ...c, status } : c));
            toast.success(`Competition ${status.toLowerCase()}`);
        } catch (error) {
            toast.error("Failed to update status");
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this competition?")) return;
        try {
            await api.delete(`/competitions/${id}`);
            setCompetitions(competitions.filter(c => c._id !== id));
            toast.success("Competition deleted");
        } catch (error) {
            toast.error("Failed to delete competition");
        }
    };

    const filteredCompetitions = competitions.filter(c =>
        c.proposedName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        c.formatType?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        c.seasonYear?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800">Competitions & Tournaments</h2>
                    <p className="text-sm text-gray-500 mt-1">Review proposals and manage officially sanctioned state competitions.</p>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full">
                <div className="p-4 border-b border-gray-100 flex flex-col sm:flex-row gap-4 justify-between bg-gray-50/50">
                    <div className="relative w-full sm:w-96">
                        <Search className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <input
                            type="text"
                            placeholder="Search competitions..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all text-sm"
                        />
                    </div>
                </div>

                <div className="overflow-x-auto w-full">
                    <table className="w-full text-left text-sm whitespace-nowrap min-w-[800px]">
                        <thead className="bg-gray-50 text-gray-500 font-semibold border-b border-gray-100">
                            <tr>
                                <th className="px-6 py-4">Competition Name</th>
                                <th className="px-6 py-4">Format</th>
                                <th className="px-6 py-4">Season / Year</th>
                                <th className="px-6 py-4">Sponsor (if any)</th>
                                <th className="px-6 py-4">Status</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {loading ? (
                                <tr>
                                    <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                                        <div className="flex items-center justify-center gap-2">
                                            <Loader2 className="w-5 h-5 animate-spin text-primary" />
                                            <span>Loading competitions...</span>
                                        </div>
                                    </td>
                                </tr>
                            ) : filteredCompetitions.length === 0 ? (
                                <tr>
                                    <td colSpan={6} className="px-6 py-8 text-center text-gray-500">No competitions found</td>
                                </tr>
                            ) : (
                                filteredCompetitions.map((comp) => (
                                    <tr key={comp._id} className="hover:bg-gray-50/50 transition-colors">
                                        <td className="px-6 py-4 font-bold text-gray-800">
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded bg-gray-100 flex shrink-0 items-center justify-center text-gray-400 overflow-hidden">
                                                    {comp.sponsorLogoUrl ? (
                                                        <img src={comp.sponsorLogoUrl} alt={comp.proposedName} className="w-full h-full object-cover" />
                                                    ) : (
                                                        <Trophy className="w-4 h-4 text-primary" />
                                                    )}
                                                </div>
                                                <span className="truncate max-w-[200px]">{comp.proposedName}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-gray-600">{comp.formatType}</td>
                                        <td className="px-6 py-4 text-gray-500">{comp.seasonYear}</td>
                                        <td className="px-6 py-4 text-gray-500 font-medium truncate max-w-[150px]">{comp.sponsorName || 'None'}</td>
                                        <td className="px-6 py-4">
                                            <span className={`px-3 py-1 rounded-full text-xs font-bold ${comp.status === 'Approved' ? 'bg-green-100 text-green-700' :
                                                comp.status === 'Pending' ? 'bg-yellow-100 text-yellow-800' :
                                                    'bg-red-100 text-red-700'
                                                }`}>
                                                {comp.status}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center justify-end gap-2">
                                                {comp.status !== 'Approved' && (
                                                    <button onClick={() => handleUpdateStatus(comp._id, 'Approved')} className="p-2 text-green-600 hover:bg-green-50 rounded-lg transition-colors" title="Sanction Competition">
                                                        <CheckCircle className="w-5 h-5" />
                                                    </button>
                                                )}
                                                {comp.status !== 'Rejected' && (
                                                    <button onClick={() => handleUpdateStatus(comp._id, 'Rejected')} className="p-2 text-orange-600 hover:bg-orange-50 rounded-lg transition-colors" title="Reject Competition">
                                                        <XCircle className="w-5 h-5" />
                                                    </button>
                                                )}
                                                <button onClick={() => handleDelete(comp._id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete Record">
                                                    <Trash2 className="w-5 h-5" />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

"use client";

import { Plus, Edit, Trash2, Search, Calendar as CalendarIcon, Loader2 } from "lucide-react";
import { useEffect, useState } from "react";
import api from "@/lib/api";
import toast from "react-hot-toast";

export default function AdminMatchesPage() {
    const [matches, setMatches] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");

    useEffect(() => {
        const fetchMatches = async () => {
            try {
                const res = await api.get('/matches');
                setMatches(res.data);
            } catch (error) {
                toast.error("Failed to load matches");
            } finally {
                setLoading(false);
            }
        };
        fetchMatches();
    }, []);

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this match?")) return;
        try {
            await api.delete(`/matches/${id}`);
            setMatches(matches.filter(m => m._id !== id));
            toast.success("Match deleted");
        } catch (error) {
            toast.error("Failed to delete match");
        }
    };

    const filteredMatches = matches.filter(m =>
        m.homeTeam?.clubName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        m.awayTeam?.clubName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        m.competition?.proposedName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        m.venue?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'Upcoming':
                return <span className="px-3 py-1 rounded-full text-xs font-bold bg-yellow-100 text-yellow-800">Upcoming</span>;
            case 'Live':
                return <span className="px-3 py-1 rounded-full text-xs font-bold bg-red-100 text-red-700 animate-pulse">Live</span>;
            case 'Completed':
                return <span className="px-3 py-1 rounded-full text-xs font-bold bg-green-100 text-green-700">Completed</span>;
            case 'Postponed':
                return <span className="px-3 py-1 rounded-full text-xs font-bold bg-gray-100 text-gray-700">Postponed</span>;
            default:
                return <span className="px-3 py-1 rounded-full text-xs font-bold bg-gray-100 text-gray-700">{status}</span>;
        }
    }

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h2 className="text-2xl font-bold text-gray-800">Match Fixtures & Results</h2>
                <button className="bg-primary hover:bg-primary-dark text-white font-bold py-2.5 px-5 rounded-lg flex items-center gap-2 transition-colors shadow-sm">
                    <Plus className="w-5 h-5" />
                    Record New Match
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full">
                <div className="p-4 border-b border-gray-100 flex flex-col sm:flex-row gap-4 justify-between bg-gray-50/50">
                    <div className="relative w-full sm:w-96">
                        <Search className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <input
                            type="text"
                            placeholder="Search by team, competition, or venue..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all text-sm"
                        />
                    </div>
                    <button className="flex items-center gap-2 px-4 py-2 border border-gray-200 rounded-lg hover:bg-gray-50 text-gray-600 text-sm font-medium transition-colors whitespace-nowrap">
                        <CalendarIcon className="w-4 h-4" />
                        Filter by Date
                    </button>
                </div>

                <div className="overflow-x-auto w-full">
                    <table className="w-full text-left text-sm whitespace-nowrap min-w-[800px]">
                        <thead className="bg-gray-50 text-gray-500 font-semibold border-b border-gray-100">
                            <tr>
                                <th className="px-6 py-4">Matchup (Home vs Away)</th>
                                <th className="px-6 py-4">Competition</th>
                                <th className="px-6 py-4">Date & Time</th>
                                <th className="px-6 py-4">Status / Score</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {loading ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-8 text-center text-gray-500">
                                        <div className="flex items-center justify-center gap-2">
                                            <Loader2 className="w-5 h-5 animate-spin text-primary" />
                                            <span>Loading matches...</span>
                                        </div>
                                    </td>
                                </tr>
                            ) : filteredMatches.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-8 text-center text-gray-500">No matches found</td>
                                </tr>
                            ) : (
                                filteredMatches.map((match) => (
                                    <tr key={match._id} className="hover:bg-gray-50/50 transition-colors">
                                        <td className="px-6 py-4">
                                            <div className="font-bold text-gray-800">
                                                {match.homeTeam?.clubName || 'Unknown'} <span className="text-gray-400 font-normal mx-1">vs</span> {match.awayTeam?.clubName || 'Unknown'}
                                            </div>
                                            <div className="text-xs text-gray-500 mt-1">{match.venue}</div>
                                        </td>
                                        <td className="px-6 py-4 text-gray-600 font-medium truncate max-w-[200px]">{match.competition?.proposedName || 'None'}</td>
                                        <td className="px-6 py-4 text-gray-500">
                                            {new Date(match.matchDate).toLocaleDateString()}
                                            {' - '}
                                            {match.matchTime}
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col gap-1 items-start">
                                                {getStatusBadge(match.status)}
                                                {(match.status === 'Completed' || match.status === 'Live') && (
                                                    <span className="text-xs font-bold text-gray-800 bg-gray-100 px-2 py-0.5 rounded">
                                                        {match.homeScore} - {match.awayScore}
                                                    </span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center justify-end gap-2">
                                                <button className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" title="Edit Match">
                                                    <Edit className="w-4 h-4" />
                                                </button>
                                                <button onClick={() => handleDelete(match._id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete Match">
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

"use client";

import { Plus, Edit, Trash2, Search, Filter, Loader2, Image as ImageIcon } from "lucide-react";
import { useEffect, useState } from "react";
import api from "@/lib/api";
import toast from "react-hot-toast";

export default function AdminNewsPage() {
    const [newsItems, setNewsItems] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState("");

    useEffect(() => {
        const fetchNews = async () => {
            try {
                const res = await api.get('/news');
                setNewsItems(res.data);
            } catch (error) {
                toast.error("Failed to load news");
            } finally {
                setLoading(false);
            }
        };
        fetchNews();
    }, []);

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this article?")) return;
        try {
            await api.delete(`/news/${id}`);
            setNewsItems(newsItems.filter(n => n._id !== id));
            toast.success("Article deleted");
        } catch (error) {
            toast.error("Failed to delete article");
        }
    };

    const filteredNews = newsItems.filter(n =>
        n.title?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        n.category?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h2 className="text-2xl font-bold text-gray-800">News & Media Management</h2>
                <button className="bg-primary hover:bg-primary-dark text-white font-bold py-2.5 px-5 rounded-lg flex items-center gap-2 transition-colors shadow-sm">
                    <Plus className="w-5 h-5" />
                    Add News Article
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col h-full">
                <div className="p-4 border-b border-gray-100 flex flex-col sm:flex-row gap-4 justify-between bg-gray-50/50">
                    <div className="relative w-full sm:w-96">
                        <Search className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                        <input
                            type="text"
                            placeholder="Search articles..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all text-sm"
                        />
                    </div>
                    <button className="flex items-center gap-2 px-4 py-2 border border-gray-200 rounded-lg hover:bg-gray-50 text-gray-600 text-sm font-medium transition-colors whitespace-nowrap">
                        <Filter className="w-4 h-4" />
                        Filter Category
                    </button>
                </div>

                <div className="overflow-x-auto w-full">
                    <table className="w-full text-left text-sm whitespace-nowrap min-w-[800px]">
                        <thead className="bg-gray-50 text-gray-500 font-semibold border-b border-gray-100">
                            <tr>
                                <th className="px-6 py-4">Article</th>
                                <th className="px-6 py-4">Title</th>
                                <th className="px-6 py-4">Category</th>
                                <th className="px-6 py-4">Date</th>
                                <th className="px-6 py-4">Status</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {loading ? (
                                <tr>
                                    <td colSpan={6} className="px-6 py-8 text-center text-gray-500">
                                        <div className="flex items-center justify-center gap-2">
                                            <Loader2 className="w-5 h-5 animate-spin text-primary" />
                                            <span>Loading news...</span>
                                        </div>
                                    </td>
                                </tr>
